### Backend (Node.js + Express.js)

First, let's set up a basic CRUD API using Express.js and Node.js.

#### Install Dependencies

```bash
npm install express mongoose body-parser
```

#### server.js

```javascript
const express = require('express');
const mongoose = require('mongoose');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.json());

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/room-management', { useNewUrlParser: true, useUnifiedTopology: true });

// Define Room Schema
const RoomSchema = new mongoose.Schema({
  name: String,
  capacity: Number,
  availability: Boolean,
  bookings: [String] // Simplified for demonstration
});

const Room = mongoose.model('Room', RoomSchema);

// Routes
app.get('/rooms', async (req, res) => {
  const rooms = await Room.find();
  res.send(rooms);
});

app.post('/rooms', async (req, res) => {
  const room = new Room(req.body);
  await room.save();
  res.status(201).send(room);
});

app.put('/rooms/:id', async (req, res) => {
  const room = await Room.findByIdAndUpdate(req.params.id, req.body, { new: true });
  res.send(room);
});

app.delete('/rooms/:id', async (req, res) => {
  await Room.findByIdAndDelete(req.params.id);
  res.send({ message: 'Room deleted' });
});

